#!/bin/bash
IFS=. read -r _i1 _i2 _i3 _i4 <<< "$1"; c=$2; o1=$((255<<(c<8?8-c:0)&255)); o2=$((255<<(c<16?16-c:0)&255)); o3=$((255<<(c<24?24-c:0)&255)); o4=$((255<<(c<32?32-c:0)&255)); n1=$((_i1&o1)); n2=$((_i2&o2)); n3=$((_i3&o3)); n4=$((_i4&o4)); b1=$((n1|(255&~o1))); b2=$((n2|(255&~o2))); b3=$((n3|(255&~o3))); b4=$((n4|(255&~o4))); printf "%d.%d.%d.%d - %d.%d.%d.%d" "$n1" "$n2" "$n3" "$((n4+1))" "$b1" "$b2" "$b3" "$((b4-1))"
